/// <summary>
/// Represents a company, team, or organizational unit.
/// </summary>
[Description("Represents a company, team, or organizational unit.")]
public record Organization
{
    [Key]
    [Description("Unique identifier for the organization")]
    public string Id { get; init; } = string.Empty;

    [Required]
    [Description("Name of the organization")]
    public string Name { get; init; } = string.Empty;

    [Description("Brief description of the organization")]
    public string? Description { get; init; }

    [Description("Organization website URL")]
    public string? Website { get; init; }

    [Description("URL or data URI for organization logo")]
    public string? Logo { get; init; }

    [Description("Icon name for visual representation")]
    public string Icon { get; init; } = "Building";

    [Description("Timestamp when the organization was created")]
    public DateTimeOffset CreatedAt { get; init; } = DateTimeOffset.UtcNow;
}
